// 获取从 Webhook 节点传入的数据
const rawData = $('Webhook').first().json.body;

// 获取文件名
const fileName = $input.first().binary.file.fileName;

// 确保输入数据是数组
let inputData;
if (Array.isArray(rawData.Data)) {
  inputData = rawData.Data;
} else {
  inputData = [rawData];
}

// 遍历数据并转换 Data 字段，同时更新 Detail 字段
const result = inputData.map(item => {
  const dataObject = JSON.parse(item.Data);
  // 保留原 Detail 数据
  const originalDetail = dataObject.Detail;
  // 新增 file 字段
  dataObject.file = fileName;
  return {
    ...item,
    Data: {
      ...dataObject,
      Detail: originalDetail, // 保留原始 Detail
      file: fileName // 新增 file 字段
    }
  };
});

// 将结果返回
return result;

// 构造目标格式
